import{_ as a,o as e,c as r,b as t}from"./app-54a9d45b.js";const h="/noniBlog/assets/browser-79c07cd7.png",d={},n=t('<h1 id="浏览器" tabindex="-1"><a class="header-anchor" href="#浏览器" aria-hidden="true">#</a> 浏览器</h1><h2 id="输入url后发生了什么" tabindex="-1"><a class="header-anchor" href="#输入url后发生了什么" aria-hidden="true">#</a> 输入URL后发生了什么</h2><p>解析url；通过DNS查询找到IP地址；进行TCP连接建立请求并发送；得到响应数据后进行渲染。</p><h3 id="dns" tabindex="-1"><a class="header-anchor" href="#dns" aria-hidden="true">#</a> DNS</h3><p>缓存 -&gt; 根域DNS服务器(.) -&gt; 顶级域DNS服务器(.com) -&gt; 权威域DNS服务器(xxx.com) -&gt; 得到ip</p><h2 id="渲染过程-关键渲染路径" tabindex="-1"><a class="header-anchor" href="#渲染过程-关键渲染路径" aria-hidden="true">#</a> 渲染过程（关键渲染路径）</h2><p>HTML 解析-&gt;DOM树</p><p>CSS 解析 -&gt; CSSOM树（CSS对象模型）</p><p>根据DOM树和CSSOM树构建渲染树</p><p>进行<strong>布局计算</strong>，根据计算结果进行<strong>绘制</strong></p><p>包含多个层的页面会进行<strong>合成</strong></p><blockquote><p>绘制 https://juejin.cn/post/6938009725745233934#heading-7</p></blockquote><h2 id="浏览器进程" tabindex="-1"><a class="header-anchor" href="#浏览器进程" aria-hidden="true">#</a> 浏览器进程</h2><p>渲染进程（GUI线程在这里）</p><p>网络进程</p><p>浏览器主进程</p><p>GPU进程</p><p>插件进程</p><p><img src="'+h+'" alt="图片"></p><h3 id="gpu进程跟gui线程的区别" tabindex="-1"><a class="header-anchor" href="#gpu进程跟gui线程的区别" aria-hidden="true">#</a> GPU进程跟GUI线程的区别</h3><p>GUI线程：在渲染进程里，每个标签页一个，负责执行js代码，解析DOM，样式计算，布局，绘制指令生成</p><p>GPU进程：全局只有一个，绘制UI界面，负责合成图层、硬件加速、把内容渲染到屏幕上</p><h3 id="重排-重绘-合成" tabindex="-1"><a class="header-anchor" href="#重排-重绘-合成" aria-hidden="true">#</a> 重排 重绘 合成</h3><ul><li>重排<strong>会改变元素的几何位置</strong>，需要更新完整的渲染流水线，所以开销也是最大的</li><li>重绘只是<strong>修改元素的颜色等非位置属性</strong>，所以省去了布局和分层阶段，开销比重排小</li><li>合成只会<strong>由已提升会合成层的transform或opacity触发，只涉及几何变换或透明度变换</strong>，会跳过前面的流程，直接进入合成阶段，开销最小。（<strong>transform或opacity若未提升为合成层，则依然会触发paint</strong>）</li></ul><h1 id="网络" tabindex="-1"><a class="header-anchor" href="#网络" aria-hidden="true">#</a> 网络</h1><h2 id="http" tabindex="-1"><a class="header-anchor" href="#http" aria-hidden="true">#</a> HTTP</h2><h3 id="http是什么" tabindex="-1"><a class="header-anchor" href="#http是什么" aria-hidden="true">#</a> HTTP是什么</h3><p>超文本传输协议。在<strong>两点</strong>之间<strong>传输</strong>文字、图片、视频、音频等<strong>超文本</strong>数据的<strong>约定和规范</strong>。</p><h3 id="http常见状态码" tabindex="-1"><a class="header-anchor" href="#http常见状态码" aria-hidden="true">#</a> HTTP常见状态码</h3><table><thead><tr><th>1xx</th><th>协议处理的中间状态</th></tr></thead><tbody><tr><td>2xx</td><td>成功，报文已经收到并被正确处理</td></tr><tr><td>3xx</td><td>重定向，资源位置发生变动，需要重新发请求</td></tr><tr><td>4xx</td><td>客户端错误，发送的报文有问题，服务器无法处理</td></tr><tr><td>5xx</td><td>服务端错误，服务器处理请求时内部发生错误</td></tr></tbody></table><h4 id="_200" tabindex="-1"><a class="header-anchor" href="#_200" aria-hidden="true">#</a> 200</h4><p>200OK，成功</p><h4 id="_204" tabindex="-1"><a class="header-anchor" href="#_204" aria-hidden="true">#</a> 204</h4><p>No Content，响应头没有body数据</p><h4 id="_206" tabindex="-1"><a class="header-anchor" href="#_206" aria-hidden="true">#</a> 206</h4><p>Partial Content，返回的body数据只有部分内容</p><h4 id="_301" tabindex="-1"><a class="header-anchor" href="#_301" aria-hidden="true">#</a> 301</h4><p>Moved Permanently，永久重定向，请求的资源已经不在了</p><h4 id="_302" tabindex="-1"><a class="header-anchor" href="#_302" aria-hidden="true">#</a> 302</h4><p>Found，临时重定向，请求的资源还在但是需要重定向 （301和302都会指明要跳转的url，浏览器会自动重定向）</p><h4 id="_304" tabindex="-1"><a class="header-anchor" href="#_304" aria-hidden="true">#</a> 304</h4><p>Not Modified，缓存重定向</p><h4 id="_400" tabindex="-1"><a class="header-anchor" href="#_400" aria-hidden="true">#</a> 400</h4><p>Bad Request，报文有误，笼统的错误</p><h4 id="_403" tabindex="-1"><a class="header-anchor" href="#_403" aria-hidden="true">#</a> 403</h4><p>Forbidden，服务器禁止访问资源</p><h4 id="_404" tabindex="-1"><a class="header-anchor" href="#_404" aria-hidden="true">#</a> 404</h4><p>Not Found，找不到请求的资源</p><h4 id="_500" tabindex="-1"><a class="header-anchor" href="#_500" aria-hidden="true">#</a> 500</h4><p>Internal Server Error，笼统的错误</p><h4 id="_501" tabindex="-1"><a class="header-anchor" href="#_501" aria-hidden="true">#</a> 501</h4><p>Not Implemented，请求的功能还不支持</p><h4 id="_502" tabindex="-1"><a class="header-anchor" href="#_502" aria-hidden="true">#</a> 502</h4><p>Bad Gateway，服务器作为网关或代理返回的错误</p><h4 id="_503" tabindex="-1"><a class="header-anchor" href="#_503" aria-hidden="true">#</a> 503</h4><p>Service Unavailable，服务器正忙无法响应</p>',56),i=[n];function s(o,p){return e(),r("div",null,i)}const l=a(d,[["render",s],["__file","liulanqihewangluo.html.vue"]]);export{l as default};
